import { config, setBillingAddress } from '@/checkout/api';
import { BillToShippingAddress as BillToShippingAddressComponent } from '@/checkout/components/BillToShippingAddress';
import { Cart, NegotiableQuote } from '@/checkout/data/models';
import {
  getLatestCheckoutUpdate,
  getValue,
  hasPendingUpdates,
  hasShippingAddress,
  notifyValues,
} from '@/checkout/lib';
import { isSetAddressRequestPending } from '@/checkout/store/ui';
import { useText } from '@adobe-commerce/elsie/i18n';
import { Container } from '@adobe-commerce/elsie/lib';
import { events } from '@adobe-commerce/event-bus';
import { HTMLAttributes } from 'preact/compat';
import { useCallback, useEffect, useRef, useState } from 'preact/hooks';

interface CartSyncError {
  error: Error;
}

export interface BillToShippingAddressProps
  extends Omit<HTMLAttributes<HTMLDivElement>, 'onChange'> {
  active?: boolean;
  autoSync?: boolean;
  onCartSyncError?: (error: CartSyncError) => void;
  onChange?: (checked: boolean) => void;
}

export const BillToShippingAddress: Container<BillToShippingAddressProps> = ({
  active = true,
  autoSync = true,
  onCartSyncError,
  onChange,
}) => {
  const [error, setError] = useState<string | null>(null);
  const [isVirtual, setIsVirtual] = useState(false);
  const [isChecked, setIsChecked] = useState<boolean | undefined>();

  const hasInitialCartData = useRef(false);

  const isDisabled = hasPendingUpdates.value || isSetAddressRequestPending.value;

  const { cartSyncError } = useText({
    cartSyncError: 'Checkout.BillToShippingAddress.cartSyncError',
  });

  const handleDismissError = useCallback(() => {
    setError(null);
  }, []);

  const handleChange = useCallback(
    (isBillToShipping: boolean) => {
      setError(null);
      setIsChecked(isBillToShipping);

      onChange?.(isBillToShipping);

      if (!autoSync || !isBillToShipping || !hasShippingAddress()) {
        return;
      }

      setBillingAddress({ sameAsShipping: true }).catch((error: any) => {
        setIsChecked(false);
        onCartSyncError?.({ error });

        if (!onCartSyncError) {
          setError(cartSyncError);
        }
      });
    },
    [autoSync, cartSyncError, onCartSyncError, onChange]
  );

  const handleCheckoutData = useCallback(
    (data: Cart | NegotiableQuote | null) => {
      const isCartEmpty = !data || data.isEmpty;
      const isCartVirtual = !!data?.isVirtual;

      if (isCartEmpty || isCartVirtual) {
        setIsVirtual(isCartVirtual);
        setIsChecked(false);
        hasInitialCartData.current = false;
        return;
      }

      // If we've already set the initial state from cart data, don't override it.
      // This preserves any changes the user might have made.
      if (hasInitialCartData.current) {
        return;
      }

      const cart = data as Cart;
      const shippingAddress = cart.shippingAddresses?.[0];
      const hasBillingAddress = !!cart.billingAddress;

      let initialIsChecked: boolean;

      if (!shippingAddress) {
        const { defaults } = config.getConfig();
        initialIsChecked = defaults!.isBillToShipping!;
      } else {
        initialIsChecked = shippingAddress.sameAsBilling ?? !hasBillingAddress;
      }

      setIsChecked(initialIsChecked);
      hasInitialCartData.current = true;

      if (
        autoSync &&
        initialIsChecked &&
        shippingAddress &&
        !hasBillingAddress
      ) {
        setBillingAddress({ sameAsShipping: true }).catch(() => {});
      }
    },
    // eslint-disable-next-line react-hooks/exhaustive-deps
    []
  );

  useEffect(() => {
    if (!active || isChecked === undefined) return;
    notifyValues({ isBillToShipping: isChecked });
  }, [active, isChecked]);

  useEffect(() => {
    if (!active) return;

    const pastUpdate = getLatestCheckoutUpdate();

    if (pastUpdate) {
      // When component becomes active, restore key state so handleCheckoutData can work properly
      const userBillToShipping = getValue('isBillToShipping');
      if (userBillToShipping != null) {
        setIsChecked(userBillToShipping);
      }
      handleCheckoutData(pastUpdate);
      return;
    }

    const onCheckoutInit = events.on(
      'checkout/initialized',
      handleCheckoutData,
      { eager: true }
    );

    return () => {
      onCheckoutInit?.off();
    };
  }, [active, handleCheckoutData]);

  useEffect(() => {
    if (!active) return;

    const onCheckoutUpdated = events.on(
      'checkout/updated',
      handleCheckoutData,
      {
        eager: false,
      }
    );

    return () => {
      onCheckoutUpdated?.off();
    };
  }, [active, handleCheckoutData]);

  return (
    <BillToShippingAddressComponent
      checked={isChecked}
      disabled={isDisabled}
      error={error}
      initialized={isChecked !== undefined}
      visible={active && !isVirtual}
      onChange={handleChange}
      onDismissError={handleDismissError}
    />
  );
};
